const person = {
  name: 'John Doe',
  age: 30,
  occupation: 'Developer'
};

// Stringified JSON (string)
const jsonString = JSON.stringify(person);
console.log(jsonString);
// Output: '{"name":"John Doe","age":30,"occupation":"Developer"}'
